#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
const int mod = 666623333;
bool flag[10000005];
int prim[10000005];
int Phi[10000005];
int val[10000005];
int tot;
void getprim () {
	int i, j, m;
	flag[0] = 1;
	flag[1] = 1;
	for (i = 2; i < 1e7; i++) {
		if (flag[i] == 0) {
			prim[tot++] = i;
		}
		for (int j = 0; j < tot && (i * prim[j] < 1e7); j++) {
			m = i * prim[j];
			flag[m] = 1;
			if (i % prim[j] == 0) {
				break;
			}
		}
	}
}
signed main() {
	int l, r, ans = 0;
	cin >> l >> r;
	getprim();
	for (int i = 0; i <= r - l; i++) {
		Phi[i] = val[i] = i + l;
	}
	for (int i = 0; i < tot && prim[i] * prim[i] <= r; i++) {
		int p = prim[i];
		for (int j = (p - l % p) % p; j <= r - l; j += p) {
			Phi[j] = Phi[j] / p * (p - 1);
			while (val[j] % p == 0) {
				val[j] /= p;
			}
		}
	}
	for (int i = 0; i <= r - l; i++) {
		if (val[i] != 1) {
			Phi[i] = Phi[i] / val[i] * (val[i] - 1);
		}
	}
	for (int i = 0; i <= r - l; i++) {
		ans = (ans + i + l - Phi[i]) % mod; 
	} 
	cout << ans;
	return 0;
}
